import React, { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar } from 'recharts';

const TrendingTopics = ({ data }) => {
  const [selectedView, setSelectedView] = useState('topics');
  const [hoveredTopic, setHoveredTopic] = useState(null);
  const [animationStep, setAnimationStep] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => setAnimationStep(1), 300);
    return () => clearTimeout(timer);
  }, []);

  // Generate trending topics data based on countries
  const trendingTopics = [
    { topic: 'AI Technology', popularity: 95, growth: '+12%', category: 'Tech' },
    { topic: 'Climate Change', popularity: 88, growth: '+8%', category: 'News' },
    { topic: 'Gaming Reviews', popularity: 82, growth: '+15%', category: 'Gaming' },
    { topic: 'Cooking Tutorials', popularity: 76, growth: '+5%', category: 'Lifestyle' },
    { topic: 'Music Covers', popularity: 74, growth: '+9%', category: 'Music' },
    { topic: 'Fitness Tips', popularity: 71, growth: '+7%', category: 'Health' },
    { topic: 'Travel Vlogs', popularity: 68, growth: '+11%', category: 'Travel' },
    { topic: 'DIY Projects', popularity: 65, growth: '+6%', category: 'Lifestyle' },
    { topic: 'Movie Reviews', popularity: 62, growth: '+4%', category: 'Entertainment' },
    { topic: 'Science Explained', popularity: 58, growth: '+13%', category: 'Education' }
  ];

  // Trending timeline data
  const trendingTimeline = [
    { week: 'Week 1', AI: 70, Gaming: 65, Music: 60, Lifestyle: 55 },
    { week: 'Week 2', AI: 75, Gaming: 68, Music: 62, Lifestyle: 58 },
    { week: 'Week 3', AI: 82, Gaming: 72, Music: 64, Lifestyle: 61 },
    { week: 'Week 4', AI: 88, Gaming: 75, Music: 67, Lifestyle: 63 },
    { week: 'Week 5', AI: 95, Gaming: 82, Music: 74, Lifestyle: 68 }
  ];

  // Regional preferences radar data
  const regionalData = [
    { region: 'North America', AI: 95, Gaming: 82, Music: 74, Lifestyle: 68, Education: 71 },
    { region: 'Europe', AI: 88, Gaming: 76, Music: 89, Lifestyle: 75, Education: 84 },
    { region: 'Asia', AI: 92, Gaming: 95, Music: 68, Lifestyle: 65, Education: 78 }
  ];

  const colors = ['#667eea', '#f093fb', '#4facfe', '#43e97b', '#ffc658'];

  const formatNumber = (value) => {
    if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
    if (value >= 1e3) return `${(value / 1e3).toFixed(0)}K`;
    return value.toString();
  };

  const getTopicColor = (index) => colors[index % colors.length];

  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      return (
        <div style={{
          backgroundColor: 'rgba(0, 0, 0, 0.9)',
          color: 'white',
          padding: '12px',
          borderRadius: '8px',
          fontSize: '12px',
          boxShadow: '0 4px 12px rgba(0,0,0,0.3)'
        }}>
          <p style={{ fontWeight: 'bold', marginBottom: '8px', color: '#ffd700' }}>
            {label}
          </p>
          {payload.map((entry, index) => (
            <p key={index} style={{ margin: '4px 0', color: entry.color }}>
              {entry.dataKey}: {entry.value}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div>
      <h2>Trending Topics & Content Analysis</h2>

      {/* View Selection */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        gap: '15px', 
        marginBottom: '30px',
        flexWrap: 'wrap'
      }}>
        {[
          { id: 'topics', label: 'Hot Topics' },
          { id: 'timeline', label: 'Trend Timeline' },
          { id: 'regional', label: 'Regional Insights' }
        ].map(view => (
          <button
            key={view.id}
            onClick={() => setSelectedView(view.id)}
            style={{
              padding: '12px 24px',
              border: 'none',
              borderRadius: '25px',
              background: selectedView === view.id 
                ? 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)'
                : 'linear-gradient(135deg, #95a5a6 0%, #7f8c8d 100%)',
              color: 'white',
              cursor: 'pointer',
              fontWeight: '600',
              fontSize: '13px',
              textTransform: 'uppercase',
              letterSpacing: '1px',
              transition: 'all 0.3s ease',
              transform: selectedView === view.id ? 'scale(1.05)' : 'scale(1)',
              boxShadow: selectedView === view.id 
                ? '0 8px 20px rgba(240, 147, 251, 0.3)'
                : '0 4px 10px rgba(149, 165, 166, 0.2)'
            }}
          >
            {view.label}
          </button>
        ))}
      </div>

      <div className="chart-container" style={{ 
        opacity: animationStep ? 1 : 0, 
        transform: animationStep ? 'translateY(0)' : 'translateY(20px)',
        transition: 'all 0.8s ease'
      }}>
        {selectedView === 'topics' && (
          <div style={{ padding: '20px' }}>
            <h3 style={{ textAlign: 'center', marginBottom: '30px', color: '#2c3e50' }}>
              Most Trending Topics Right Now
            </h3>
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: '20px'
            }}>
              {trendingTopics.map((topic, index) => (
                <div
                  key={topic.topic}
                  style={{
                    background: hoveredTopic === index 
                      ? `linear-gradient(135deg, ${getTopicColor(index)}, ${getTopicColor(index + 1)})`
                      : 'linear-gradient(145deg, #ffffff 0%, #f8f9ff 100%)',
                    padding: '20px',
                    borderRadius: '15px',
                    boxShadow: hoveredTopic === index 
                      ? '0 15px 30px rgba(0,0,0,0.2)'
                      : '0 5px 15px rgba(0,0,0,0.1)',
                    cursor: 'pointer',
                    transition: 'all 0.3s ease',
                    transform: hoveredTopic === index ? 'translateY(-5px) scale(1.02)' : 'translateY(0)',
                    color: hoveredTopic === index ? 'white' : '#2c3e50',
                    border: `2px solid ${getTopicColor(index)}20`
                  }}
                  onMouseEnter={() => setHoveredTopic(index)}
                  onMouseLeave={() => setHoveredTopic(null)}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                    <span style={{ 
                      fontSize: '12px', 
                      fontWeight: '600', 
                      textTransform: 'uppercase',
                      opacity: hoveredTopic === index ? 0.9 : 0.7
                    }}>
                      {topic.category}
                    </span>
                    <span style={{ 
                      fontSize: '14px', 
                      fontWeight: 'bold',
                      color: hoveredTopic === index ? '#90EE90' : '#27ae60'
                    }}>
                      {topic.growth}
                    </span>
                  </div>

                  <h4 style={{ 
                    margin: '0 0 15px 0', 
                    fontSize: '18px', 
                    fontWeight: '700' 
                  }}>
                    {topic.topic}
                  </h4>

                  <div style={{ position: 'relative' }}>
                    <div style={{
                      width: '100%',
                      height: '8px',
                      backgroundColor: hoveredTopic === index ? 'rgba(255,255,255,0.3)' : '#e0e0e0',
                      borderRadius: '4px',
                      overflow: 'hidden'
                    }}>
                      <div style={{
                        width: `${topic.popularity}%`,
                        height: '100%',
                        background: hoveredTopic === index 
                          ? 'linear-gradient(90deg, rgba(255,255,255,0.8), rgba(255,255,255,1))'
                          : `linear-gradient(90deg, ${getTopicColor(index)}, ${getTopicColor(index + 1)})`,
                        borderRadius: '4px',
                        transition: 'all 0.8s ease',
                        animation: `growBar 1.5s ease-out ${index * 0.1}s both`
                      }}>
                      </div>
                    </div>
                    <span style={{ 
                      position: 'absolute', 
                      right: '0', 
                      top: '-25px', 
                      fontSize: '14px', 
                      fontWeight: 'bold' 
                    }}>
                      {topic.popularity}%
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {selectedView === 'timeline' && (
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={trendingTimeline} margin={{ top: 20, right: 30, bottom: 40, left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(102, 126, 234, 0.1)" />
              <XAxis dataKey="week" tick={{ fontSize: 12 }} />
              <YAxis tick={{ fontSize: 12 }} />
              <Tooltip content={<CustomTooltip />} />
              <Line 
                type="monotone" 
                dataKey="AI" 
                stroke="#667eea" 
                strokeWidth={3}
                dot={{ fill: '#667eea', strokeWidth: 2, r: 6 }}
                animationDuration={1500}
              />
              <Line 
                type="monotone" 
                dataKey="Gaming" 
                stroke="#f093fb" 
                strokeWidth={3}
                dot={{ fill: '#f093fb', strokeWidth: 2, r: 6 }}
                animationDuration={1500}
                animationDelay={200}
              />
              <Line 
                type="monotone" 
                dataKey="Music" 
                stroke="#4facfe" 
                strokeWidth={3}
                dot={{ fill: '#4facfe', strokeWidth: 2, r: 6 }}
                animationDuration={1500}
                animationDelay={400}
              />
              <Line 
                type="monotone" 
                dataKey="Lifestyle" 
                stroke="#43e97b" 
                strokeWidth={3}
                dot={{ fill: '#43e97b', strokeWidth: 2, r: 6 }}
                animationDuration={1500}
                animationDelay={600}
              />
            </LineChart>
          </ResponsiveContainer>
        )}

        {selectedView === 'regional' && (
          <ResponsiveContainer width="100%" height="100%">
            <RadarChart data={regionalData[0]} margin={{ top: 40, right: 40, bottom: 40, left: 40 }}>
              <PolarGrid stroke="rgba(102, 126, 234, 0.2)" />
              <PolarAngleAxis dataKey="subject" tick={{ fontSize: 12, fill: '#2c3e50' }} />
              <PolarRadiusAxis tick={{ fontSize: 10 }} />
              <Radar
                name="North America"
                dataKey="AI"
                stroke="#667eea"
                fill="#667eea"
                fillOpacity={0.1}
                strokeWidth={2}
              />
              <Radar
                name="North America"
                dataKey="Gaming"
                stroke="#f093fb"
                fill="#f093fb"
                fillOpacity={0.1}
                strokeWidth={2}
              />
              <Radar
                name="North America"
                dataKey="Music"
                stroke="#4facfe"
                fill="#4facfe"
                fillOpacity={0.1}
                strokeWidth={2}
              />
              <Radar
                name="North America"
                dataKey="Lifestyle"
                stroke="#43e97b"
                fill="#43e97b"
                fillOpacity={0.1}
                strokeWidth={2}
              />
              <Radar
                name="North America"
                dataKey="Education"
                stroke="#ffc658"
                fill="#ffc658"
                fillOpacity={0.1}
                strokeWidth={2}
              />
              <Tooltip />
            </RadarChart>
          </ResponsiveContainer>
        )}
      </div>

      <style jsx>{`
        @keyframes growBar {
          from { width: 0%; }
          to { width: ${props => props.width}%; }
        }
      `}</style>
    </div>
  );
};

export default TrendingTopics;
